% do_1d_bst_run_repair_steps.m

% you need repair_steps_12_data2.m 
% in the same directory

% It has to be fs=500 Hz. It closes the gap of every 10 seconds
% that are made by drift and AD conversion limit

% the below is taking the imported continuous file and run the matlab
% command within Brainstorm loop

% Script generated by Brainstorm (14-Jul-2021)

% Run this while Brainstorm opened
% universal name
% list subj#1 subj#2 in the order of the file
pair = {
        'S07', 'S08';
        'S09', 'S10';
        'S13', 'S14';
        'S17', 'S18';
        'S19', 'S20';
        'S23', 'S24';
        };
npair = size(pair,1);

player = {'SubA';'SubB'};

melnames = [
    3,4,1,2; % pair 4 (S07-S08)
    1,2,3,4; % pair 5 (S09-S10)
    1,2,3,4; % pair 7 (S13-S14)
    1,2,3,4; % pair 9 (S17-S18)
    3,4,1,2; % pair 10 (S19-S20)
    3,4,1,2; % pair 12 (S23-S24)
     ];
npair = size(pair,1);

player = {'SubA';'SubB'};

for ipair=1:npair
    sub={pair{ipair,1};pair{ipair,2}};
    pairname = sprintf('%s_%s', sub{1}, sub{2});
    
    % loop two partners
    for isubj=1:2
        
        subjname = sub{isubj};
        playerID= player{isubj};

% Path: C:\Users\tfujioka\Documents\brainstorm_db\Duet2017a\data
% Name: S01/S01_AA1_1_Data/data_block001.mat

sFiles = {...
            sprintf('%s/%s_AA%d_1_Data/data_block001.mat',subjname,subjname,melnames(ipair,1)), ...
            sprintf('%s/%s_AA%d_2_Data/data_block001.mat',subjname,subjname,melnames(ipair,1)), ...
            sprintf('%s/%s_BC%d_1_Data/data_block001.mat',subjname,subjname,melnames(ipair,2)), ...
            sprintf('%s/%s_BC%d_2_Data/data_block001.mat',subjname,subjname,melnames(ipair,2)), ...
            sprintf('%s/%s_AA%d_1_%s_Data/data_block001.mat',subjname,pairname,melnames(ipair,3),playerID),...
            sprintf('%s/%s_AA%d_2_%s_Data/data_block001.mat',subjname,pairname,melnames(ipair,3),playerID),...
            sprintf('%s/%s_BC%d_1_%s_Data/data_block001.mat',subjname,pairname,melnames(ipair,4),playerID), ...
            sprintf('%s/%s_BC%d_2_%s_Data/data_block001.mat',subjname,pairname,melnames(ipair,4),playerID), ...
            };


             
% Start a new report
bst_report('Start', sFiles);


% Process: Run Matlab command
sFiles = bst_process('CallProcess', 'process_matlab_eval', sFiles, [], ...
    'matlab',      ['Data = repair_steps_12_data2(Data,TimeVector);'], ...
    'sensortypes', 'MEG, EEG', ...
    'overwrite',   0);

% Save and display report
ReportFile = bst_report('Save', sFiles);
% bst_report('Open', ReportFile);
% bst_report('Export', ReportFile, ExportDir);

    end % isubj
end % ipair

